isCurrentQuarter = (day: Date, q: number) =>
  getYear(day) === getYear(newDate()) && q === getQuarter(newDate());

isSelectedMonth = (day: Date, m: number, selected: Date) =>
  getMonth(selected) === m && getYear(day) === getYear(selected);

