isMonthSelected = () => {
  const { day, selected, selectedDates, selectsMultiple } = this.props;
  const monthIdx = getMonth(day);

  if (selectsMultiple) {
    return selectedDates?.some((date) =>
      this.isSelectedMonth(day, monthIdx, date),
